import React, { useState } from "react";
import { analyzeImage } from "./api";

const UploadImage = () => {
  const [file, setFile] = useState(null);
  const [report, setReport] = useState("");
  const [loading, setLoading] = useState(false);

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  const handleUpload = async () => {
    if (!file) return;
    setLoading(true);
    try {
      const response = await analyzeImage(file);
      setReport(response.data.AI_Analysis);
    } catch (error) {
      console.error("Error analyzing image:", error);
      setReport("Error analyzing image");
    }
    setLoading(false);
  };

  return (
    <div className="flex flex-col items-center">
      <label className="block mb-4">
        <span className="sr-only">Choose Image</span>
        <input 
          type="file" 
          accept="image/*"
          className="block w-full text-sm text-gray-600
                     file:mr-4 file:py-2 file:px-4
                     file:rounded-lg file:border-0
                     file:text-sm file:font-semibold
                     file:bg-blue-500 file:text-white
                     hover:file:bg-blue-600 cursor-pointer"
          onChange={handleFileChange}
        />
      </label>

      <button
        onClick={handleUpload}
        disabled={loading}
        className={`mt-4 px-6 py-3 rounded-lg text-white font-semibold transition-all
                    ${loading ? "bg-gray-400" : "bg-blue-600 hover:bg-blue-700"}`}
      >
        {loading ? "Analyzing..." : "Analyze Image"}
      </button>

      {report && (
        <div className="mt-6 bg-gray-50 p-4 rounded-lg shadow text-gray-700 text-left w-full">
          <h2 className="text-lg font-semibold">Comprehensive AI Findings</h2>
          <p className="mt-2">{report}</p>
        </div>
      )}
    </div>
  );
};

export default UploadImage;
